using System;
using System.Linq;
using System.Collections.Generic;
using System.IO;

namespace Ejercicio3
{
    public static class Datos
    {
        public static void Serializa(IEnumerable<Cliente> clientes, string fichero)
        {
            using (FileStream fs = new FileStream(fichero, FileMode.Create, FileAccess.Write))
            {
                foreach (var c in clientes) c.Serializa(fs);
            }

        }

        public static IEnumerable<Cliente> Deserizaliza(string fichero)
        {
            using (FileStream fs = new FileStream(fichero, FileMode.Open, FileAccess.Read))
            {
                while (fs.Position < fs.Length)
                    yield return new Cliente(fs);
            }
        }

